// Extract phone number and message from Green API webhook
const webhookData = $('WhatsApp Webhook').first().json;

// Green API webhook structure
const senderData = webhookData.body?.senderData || webhookData.senderData || {};
const messageData = webhookData.body?.messageData || webhookData.messageData || {};

// Extract phone number (remove @c.us suffix)
let chatId = senderData.chatId || senderData.sender || '';
let phone = chatId.replace('@c.us', '');

// Extract message text
let messageText = '';
if (messageData.textMessageData) {
  messageText = messageData.textMessageData.textMessage || '';
} else if (messageData.extendedTextMessageData) {
  messageText = messageData.extendedTextMessageData.text || '';
}

// Clean message (trim and lowercase for comparison)
const cleanMessage = messageText.trim().toLowerCase();

return {
  json: {
    phone: phone,
    chatId: chatId,
    messageText: messageText,
    cleanMessage: cleanMessage,
    rawWebhook: webhookData
  }
};

// Normalize Turkish characters to ASCII
function normalizeTurkish(str) {
  const map = { 'ç': 'c', 'Ç': 'C', 'ş': 's', 'Ş': 'S', 'ğ': 'g', 'Ğ': 'G', 'ü': 'u', 'Ü': 'U', 'ö': 'o', 'Ö': 'O', 'ı': 'i', 'İ': 'I' };
  return str.replace(/[çÇşŞğĞüÜöÖıİ]/g, c => map[c] || c);
}

// Get data from previous nodes
const lead = $('Find Lead by Phone').first().json;
const question = $('Get Current Question').first().json;
const messageData = $('Extract Phone & Message').first().json;
const env = $('ENV').first().json;

// Normalize answer (Turkish chars to ASCII)
const answer = normalizeTurkish(messageData.cleanMessage);
const currentQuestionId = parseInt(lead.current_question_id) || 1;

// Check if user wants to go back (including 'o' and 'O')
const goBackCommands = ['0', 'o', 'O', 'geri', 'back', 'onceki', 'önceki'];
const isGoingBack = goBackCommands.includes(answer.trim());

// If going back and not on first question
if (isGoingBack) {
  const prevQuestionId = currentQuestionId - 1;
  const canGoBack = prevQuestionId >= 1;

  return {
    json: {
      leadId: lead.id,
      leadPhone: lead.phone,
      leadName: lead.name,
      leadEmail: lead.email,
      chatId: messageData.phone + '@c.us',

      isGoingBack: true,
      isInvalidAnswer: false,
      canGoBack: canGoBack,
      currentQuestionId: currentQuestionId,
      prevQuestionId: prevQuestionId,
      previousTotal: parseInt(lead.total_score) || 0,

      highScoreThreshold: parseInt(env.HIGH_SCORE_THRESHOLD) || 150
    }
  };
}

// Normal answer flow
const questionWeight = parseInt(question.weight) || 1;

// Parse scoring rules
let score = 0;
let matchedOption = null;

try {
  const scoringRules = JSON.parse(question.scoring_rules || '{}');
  const rules = scoringRules.rules || [];

  // Try to match answer to options
  const options = JSON.parse(question.options || '[]');

  // Check if answer is a letter (a, b, c, d)
  const letterIndex = answer.charCodeAt(0) - 97; // 'a' = 0, 'b' = 1, etc.

  if (letterIndex >= 0 && letterIndex < options.length && answer.length === 1) {
    matchedOption = options[letterIndex];

    // Find score for this option
    for (const rule of rules) {
      if (rule.answer.toLowerCase() === matchedOption.toLowerCase() || 
          rule.answer.toLowerCase() === answer) {
        score = (rule.score || 0) * questionWeight;
        break;
      }
    }
  } else {
    // Direct text match
    for (const rule of rules) {
      if (rule.answer.toLowerCase() === answer) {
        score = (rule.score || 0) * questionWeight;
        matchedOption = answer;
        break;
      }
    }
  }
} catch (e) {
  // If parsing fails, give 0 score
  score = 0;
}

// Check if answer is invalid (no match found)
if (matchedOption === null) {
  return {
    json: {
      leadId: lead.id,
      leadPhone: lead.phone,
      leadName: lead.name,
      leadEmail: lead.email,
      chatId: messageData.phone + '@c.us',

      isGoingBack: false,
      isInvalidAnswer: true,
      currentQuestionId: currentQuestionId,
      answerText: messageData.messageText,
      previousTotal: parseInt(lead.total_score) || 0,

      highScoreThreshold: parseInt(env.HIGH_SCORE_THRESHOLD) || 150
    }
  };
}

// Calculate new total score
const currentTotal = parseInt(lead.total_score) || 0;
const newTotal = currentTotal + score;

const nextQuestionId = currentQuestionId + 1;

return {
  json: {
    leadId: lead.id,
    leadPhone: lead.phone,
    leadName: lead.name,
    leadEmail: lead.email,
    chatId: messageData.phone + '@c.us',

    isGoingBack: false,
    isInvalidAnswer: false,
    questionId: currentQuestionId,
    answerText: messageData.messageText,
    matchedOption: matchedOption,
    answerScore: score,

    previousTotal: currentTotal,
    newTotal: newTotal,
    nextQuestionId: nextQuestionId,

    highScoreThreshold: parseInt(env.HIGH_SCORE_THRESHOLD) || 150
  }
};

// Format next question message
const nextQuestion = $('Get Next Question').first().json;
const scoreData = $('Calculate Score').first().json;

let questionText = nextQuestion.question_text || '';
let options = '';

if (nextQuestion.options) {
  try {
    const optionsArray = JSON.parse(nextQuestion.options);
    options = optionsArray.map((opt, i) => {
      const letter = String.fromCharCode(97 + i); // a, b, c, d...
      return `${letter}) ${opt}`;
    }).join('\n');
  } catch (e) {
    options = nextQuestion.options;
  }
}

const questionNumber = scoreData.nextQuestionId;
// Add back hint for questions after the first one
const backHint = questionNumber > 1 ? '\n(0 ile geri donebilirsiniz)' : '';
const message = `${questionNumber}. ${questionText}\n${options}${backHint}`;

return {
  json: {
    chatId: scoreData.chatId,
    message: message,
    leadId: scoreData.leadId,
    nextQuestionId: scoreData.nextQuestionId,
    newTotal: scoreData.newTotal,
    isLastQuestion: false
  }
};

