// Last question - calculate final score and determine quality
const scoreData = $('Calculate Score').first().json;
const env = $('ENV').first().json;
const configRows = $('Get Config Messages').all();

// Get messages from Config
let highQualityMsg = '';
let lowQualityMsg = '';
for (const row of configRows) {
  if (row.json.key === 'high_quality_message') highQualityMsg = row.json.value || '';
  if (row.json.key === 'low_quality_message') lowQualityMsg = row.json.value || '';
}

const finalScore = scoreData.newTotal;
const threshold = scoreData.highScoreThreshold;
const isHighQuality = finalScore >= threshold;

let message = '';
let quality = '';
let status = '';

if (isHighQuality) {
  quality = 'high';
  status = 'scored';
  const email = encodeURIComponent(scoreData.leadEmail || '');
  const phone = encodeURIComponent(scoreData.leadPhone || '');
  const name = encodeURIComponent(scoreData.leadName || '');
  const fullUrl = `${env.CALCOM_MEETING_URL}?email=${email}&attendeePhoneNumber=${phone}&name=${name}`;

  // Replace {url} placeholder in config message, or use default
  if (highQualityMsg && highQualityMsg.includes('{url}')) {
    message = highQualityMsg.replace('{url}', fullUrl);
  } else if (highQualityMsg) {
    message = highQualityMsg;
  } else {
    message = `Tebrikler! Degerlendirmeniz tamamlandi ve sizinle gorusmek istiyoruz!\n\nAsagidaki linkten uygun bir zaman secebilirsiniz:\n${fullUrl}`;
  }
} else {
  quality = 'low';
  status = 'nurturing';
  message = lowQualityMsg || 'Tesekkurler! Bilgilerinizi aldik. Su an icin hizmetlerimiz ihtiyaclarinizla tam ortusmuyor olabilir. Sizi e-posta listemize ekledik, size ozel firsatlardan haberdar edecegiz!';
}

return {
  json: {
    chatId: scoreData.chatId,
    message: message,
    leadId: scoreData.leadId,
    finalScore: finalScore,
    quality: quality,
    status: status,
    isHighQuality: isHighQuality
  }
};

// Format current question message for invalid answer retry
const question = $('Get Current Question').first().json;
const scoreData = $('Calculate Score').first().json;

let questionText = question.question_text || '';
let options = '';

if (question.options) {
  try {
    const optionsArray = JSON.parse(question.options);
    options = optionsArray.map((opt, i) => {
      const letter = String.fromCharCode(97 + i);
      return `${letter}) ${opt}`;
    }).join('\n');
  } catch (e) {
    options = question.options;
  }
}

const questionNumber = scoreData.currentQuestionId;
const backHint = questionNumber > 1 ? '\n(0 ile geri donebilirsiniz)' : '';
const invalidHint = 'Lutfen gecerli bir secenek girin (a, b, c veya d).\n\n';
const message = `${invalidHint}${questionNumber}. ${questionText}\n${options}${backHint}`;

return {
  json: {
    chatId: scoreData.chatId,
    message: message,
    leadId: scoreData.leadId,
    currentQuestionId: scoreData.currentQuestionId
  }
};

