// Format previous question message
const prevQuestion = $('Get Previous Question').first().json;
const scoreData = $('Calculate Score').first().json;
const prevAnswer = $('Get Previous Answer').first().json;

let questionText = prevQuestion.question_text || '';
let options = '';

if (prevQuestion.options) {
  try {
    const optionsArray = JSON.parse(prevQuestion.options);
    options = optionsArray.map((opt, i) => {
      const letter = String.fromCharCode(97 + i);
      return `${letter}) ${opt}`;
    }).join('\n');
  } catch (e) {
    options = prevQuestion.options;
  }
}

const questionNumber = scoreData.prevQuestionId;
const backHint = questionNumber > 1 ? '\n(0 ile geri donebilirsiniz)' : '';
const message = `${questionNumber}. ${questionText}\n${options}${backHint}`;

// Calculate new total by subtracting previous answer score
const prevAnswerScore = parseInt(prevAnswer.score) || 0;
const newTotal = scoreData.previousTotal - prevAnswerScore;

return {
  json: {
    chatId: scoreData.chatId,
    message: message,
    leadId: scoreData.leadId,
    prevQuestionId: scoreData.prevQuestionId,
    newTotal: newTotal < 0 ? 0 : newTotal
  }
};

